"use strict";(globalThis.webpackChunksite=globalThis.webpackChunksite||[]).push([[9067],{42638(e,t,o){o.r(t),o.d(t,{assets:()=>l,contentTitle:()=>a,default:()=>d,frontMatter:()=>i,metadata:()=>n,toc:()=>c});const n=JSON.parse('{"id":"reference/cli-reference/stave-export-controls","title":"stave export-controls","description":"Export the control catalog for external solver consumption","source":"@site/../stave-guide/reference/cli-reference/stave-export-controls.md","sourceDirName":"reference/cli-reference","slug":"/reference/cli-reference/stave-export-controls","permalink":"/docs/reference/cli-reference/stave-export-controls","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":25,"frontMatter":{"title":"stave export-controls","sidebar_label":"export-controls","sidebar_position":25,"description":"Export the control catalog for external solver consumption"},"sidebar":"docs","previous":{"title":"explain","permalink":"/docs/reference/cli-reference/stave-explain"},"next":{"title":"export-sir","permalink":"/docs/reference/cli-reference/stave-export-sir"}}');var r=o(74848),s=o(28453);const i={title:"stave export-controls",sidebar_label:"export-controls",sidebar_position:25,description:"Export the control catalog for external solver consumption"},a="stave export-controls",l={},c=[];function u(e){const t={code:"code",h1:"h1",header:"header",pre:"pre",...(0,s.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(t.header,{children:(0,r.jsx)(t.h1,{id:"stave-export-controls",children:"stave export-controls"})}),"\n",(0,r.jsx)(t.pre,{children:(0,r.jsx)(t.code,{className:"language-text",children:'Export the control catalog as a JSON document \u2014 each entry carries the\ncontrol\'s predicate tree, authored intent rationale, and the optional\nforbidden_state block (the high-level "this configuration must never\nexist" claim external SMT compilers consume to generate Z3\nsatisfiability queries).\n\nThe export is metadata-only: no observation reads, no findings, no\nclock. External solvers receive a pure description of "the controls\nStave evaluates" without inheriting any of Stave\'s evaluation\nsemantics. The JSON shape itself is the stable solver-import format,\nso the top-level array is keyed `invariants` \u2014 that name is the\nsolver-side data contract, not Stave\'s user-facing vocabulary.\n\nInputs:\n  --controls, -i      Control definitions directory (default: built-in catalog)\n  --format, -f        Output format: json (default: json)\n\nOutputs:\n  stdout: control export as a JSON document (sorted by control ID).\n  stderr: errors.\n\nExit codes:\n  0   success\n  2   input error (bad flag)\n  4   internal error (load failure, projection error)\n  130 SIGINT\n\nUsage:\n  stave export-controls [flags]\n\nExamples:\n  # Built-in catalog \u2192 JSON to stdout\n  stave export-controls > controls.json\n\n  # Filter to controls that author a forbidden_state block\n  stave export-controls | jq \'[.invariants[] | select(.forbidden_state.combine != "")]\'\n\n  # Custom controls directory\n  stave export-controls --controls ./my-controls > controls.json\n\nFlags:\n  -i, --controls string   control definitions directory (empty = built-in catalog)\n  -f, --format string     output format: json (default "json")\n  -h, --help              help for export-controls\n\nGlobal Flags:\n      --allow-symlink-output   Allow writing output through symlinks (default: refuse)\n      --force                  Allow overwriting existing output files\n      --log-file string        Write logs to file (default: stderr)\n      --log-format string      Log format: text|json (default "text")\n      --log-level string       Log level: debug|info|warn|error (overrides -v)\n      --log-timestamps         Include timestamps in logs (breaks determinism)\n      --log-timings            Include timing information (breaks determinism)\n      --no-color               Disable ANSI colors in output\n      --path-mode string       Path rendering in errors/logs: base (basename only) or full (absolute paths) Resolved default may come from STAVE_* env vars, stave.yaml, user config, or built-in.\n      --quiet                  Suppress output (exit code only) Resolved default may come from STAVE_* env vars, stave.yaml, user config, or built-in.\n      --require-offline        Assert offline operation: fail if proxy env vars (HTTP_PROXY, HTTPS_PROXY, ALL_PROXY) are set\n      --sanitize               Sanitize infrastructure identifiers (bucket names, ARNs, policies) from output Resolved default may come from STAVE_* env vars, stave.yaml, user config, or built-in.\n      --strict                 Enable strict integrity checks for embedded registries and references\n  -v, --verbose count          Increase verbosity (-v=INFO, -vv=DEBUG)\n  -y, --yes                    Auto-confirm all interactive prompts (distinct from --force which controls file overwriting)\n'})})]})}function d(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,r.jsx)(t,{...e,children:(0,r.jsx)(u,{...e})}):u(e)}},28453(e,t,o){o.d(t,{R:()=>i,x:()=>a});var n=o(96540);const r={},s=n.createContext(r);function i(e){const t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:i(e.components),n.createElement(s.Provider,{value:t},e.children)}}}]);